import java.io.*;
import java.util.*;

public class XSSSecureCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Sanitize and escape user input before using it
        String sanitizedUserInput = sanitizeInput(userInput);

        System.out.println("Hello, " + sanitizedUserInput + "!");
    }

    // Method to sanitize and escape input to prevent XSS attacks
    private static String sanitizeInput(String input) {
        return input.replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;")
                    .replaceAll("&", "&amp;")
                    .replaceAll("\"", "&quot;")
                    .replaceAll("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
